#include <iostream>
#include <stack>
using namespace std;
stack<char> a;
int main()
{
    string s;
    getline(cin,s,'@');
    for(int i=0;i<=s.size()-1;i++)
    {
        if(s[i]=='(')
        {
            a.push('(');
        }
        else if(s[i]==')')
        {
            if(a.empty())
            {
                cout<<"NO";
                return 0;
            }
            else
            {
                a.pop();
            }
        }
    }
    if(a.empty())
    {
        cout<<"YES";
    }
    else
    {
        cout<<"NO";
    }
    return 0;
}
